import pytest

def test_primary_holder_can_perform_transaction(joint_account, primary_auth_token, api_client):
    account_id = joint_account["id"]
    payload = {"type": "deposit", "amount": 500.00, "currency": "USD"}
    headers = {"Authorization": f"Bearer {primary_auth_token}"}

    resp = api_client.post(
        f"/accounts/{account_id}/joint",
        json=payload,
        headers=headers
    )

    assert resp.status_code in (200, 201), (
        f"Expected 200/201, got {resp.status_code}: {resp.text}"
    )
    body = resp.json()
    assert body.get("status") in ("applied", "completed", "success"), (
        f"Unexpected status in body: {body}"
    )
    assert "transaction_id" in body, "transaction_id missing from response"

import pytest

def test_secondary_holder_cannot_modify_ownership(joint_account, secondary_auth_token, api_client):
    account_id = joint_account["id"]
    payload = {"action": "transfer_ownership", "new_primary": joint_account["secondary_holder_id"]}
    headers = {"Authorization": f"Bearer {secondary_auth_token}"}

    resp = api_client.patch(
        f"/accounts/{account_id}/joint",
        json=payload,
        headers=headers
    )

    assert resp.status_code == 403, (
        f"Expected 403 Forbidden, got {resp.status_code}: {resp.text}"
    )
    body = resp.json()
    assert "error" in body or "detail" in body, "Error descriptor missing from 403 body"
    error_msg = body.get("error", body.get("detail", "")).lower()
    assert any(kw in error_msg for kw in ("forbidden", "unauthorized", "not permitted", "insufficient")), (
        f"Error message does not indicate forbidden: {error_msg}"
    )

