import pytest

def test_secondary_holder_read_then_write_state_transition(joint_account, secondary_auth_token, api_client):
    account_id = joint_account["id"]
    headers = {"Authorization": f"Bearer {secondary_auth_token}"}

    # State: READABLE — secondary holder may GET account info
    get_resp = api_client.get(f"/accounts/{account_id}/joint", headers=headers)
    assert get_resp.status_code == 200, (
        f"Expected 200 for secondary GET, got {get_resp.status_code}: {get_resp.text}"
    )

    # State transition: attempt WRITE (ownership change) — must be rejected
    patch_payload = {"action": "transfer_ownership", "new_primary": joint_account["secondary_holder_id"]}
    patch_resp = api_client.patch(
        f"/accounts/{account_id}/joint",
        json=patch_payload,
        headers=headers
    )
    assert patch_resp.status_code == 403, (
        f"Expected 403 on ownership write attempt, got {patch_resp.status_code}: {patch_resp.text}"
    )

