import pytest

def test_decision_table_all_holder_role_and_operation_combinations(
    joint_account, primary_auth_token, secondary_auth_token, api_client
):
    account_id = joint_account["id"]
    secondary_id = joint_account["secondary_holder_id"]

    rules = [
        (primary_auth_token,   "post",  {"type": "deposit", "amount": 100.00, "currency": "USD"},                  (200, 201)),
        (primary_auth_token,   "patch", {"action": "transfer_ownership", "new_primary": secondary_id},            (200, 201, 204)),
        (secondary_auth_token, "post",  {"type": "deposit", "amount": 100.00, "currency": "USD"},                  (200, 201)),
        (secondary_auth_token, "patch", {"action": "transfer_ownership", "new_primary": secondary_id},            (403,)),
    ]

    for token, method, payload, allowed_codes in rules:
        headers = {"Authorization": f"Bearer {token}"}
        fn = getattr(api_client, method)
        resp = fn(f"/accounts/{account_id}/joint", json=payload, headers=headers)
        assert resp.status_code in allowed_codes, (
            f"[{method.upper()} token={token[:8]}...] "
            f"Expected {allowed_codes}, got {resp.status_code}: {resp.text}"
        )
